VALUES
  ('social-worker-moex-03161', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在老年人常見的疾病中，下列描述何者正確？', '["阿茲海默症、巴金森氏症都是屬於可逆性的疾病", "輕度失智症的老人，經常會被家人和專業人員疏忽", "對失智老人的活動安排不能太活潑，才不會過度刺激其病症", "手腳抖動不停是失智患者的重要徵狀"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03162', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關人類面臨死亡的過程，下列那一項描述正確？', '["Elizabeth Kubler-Ross提出人在面臨死亡過程的次序為：否認和隔離、接受、討價還價、憂鬱、憤怒", "在實務工作中，Elizabeth Kubler-Ross所提出人在面臨死亡過程會以次序性的方式出現", "臨終關懷（hospice）的概念是1960年代由英國桑德斯（Dr. Cicely Saunders）首先提出", "通常在老人機構和老人談論死亡的相關話題並不是禁忌，故社工人員不需在意"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03163', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關社會資源的描述，下列何者正確？', '["社會資源是指協助社工人員發揮個人潛能，滿足其問題需求的相關資源", "使用正式資源的優點雖需資產調查，但卻缺乏資源重分配之公平效果", "在照顧的過程中，對關係的投入、承諾為經濟性資源，而對權力運作的認知為規範性資源", "社工人員在助人專業過程中，進行外在資源連結是協助案主的重要工具"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03164', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '校園暴力問題已成為學校中令人頭痛的問題，下列那一項描述正確？', '["校園暴力事件大都發生在老師與學生之間，老師和學生都常為被害人", "校園暴力是指發生於學校內或上學期間，所發生的暴力侵害行為", "校園暴力事件的嚴重性，以官方的統計嚴重性較高", "校園暴力問題以居住在犯罪率較高的地區才會發生"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03165', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列那一項不是「出櫃」（coming out）通常需經歷的階段？', '["自我坦承", "結識圈內人", "向參考團體坦承", "公開自己的性取向"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03166', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在美國，目前法律上已經承認同性婚姻合法的州有多少個？', '["不到10個", "10～19個", "20～29個", "30個以上"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03167', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列對於「變項（variables）」的敘述，何者正確？', '["社會科學理論的目的之一在描述變項和變項之間的關聯", "變項是由屬性（attributes）所構成的邏輯群聚。例如，性別這個屬性就是男、女這兩個變項所構成", "若我們說「一個人受教育可降低偏見的機率」，在此處偏見是自變項（independent variable），而教育 是依變項（dependent variable）", "抑制變項（suppressor variable）會讓我們所知道的變項關係恰恰與原始資料所提供者相反"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03168', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某研究者在閱讀眾多相關文獻後，想透過大規模的調查找出受虐者為什麼會又回到施虐者身邊同住的理 由。這在研究的目的上，它屬於那類？', '["探索性", "描述性", "解釋性", "一般性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03169', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某研究者想研究青少年中輟的原因，他從觀察開始，然後找出其中模式，並依此提出一套暫時的結論， 在邏輯上，這是什麼方法的應用？', '["類比法", "外推法", "歸納法", "演繹法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03170', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某實務工作者執行脫貧方案，發現它能有效協助當地貧困者脫貧。現在，他打算推廣到其他地方去。但 他又害怕產生研究法中「過度概化（overgeneralization）」的謬誤，這個問題該如何解決？', '["試著給予選擇性的觀察", "試著加大樣本數、並且重複的再觀察這項方案執行的結果", "針對這個現象，請教權威", "這個情形很難避免，做了再說"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
